const body = $input.first().json.body || {};
const headers = $input.first().json.headers || {};

const token = headers['x-gpmd-secret'];
if (token !== 'GPMD_WEBHOOK_SECRET') {
  return [{ json: { ok: 'false', error: 'Unauthorized' } }];
}

const phone = (body.phone || '').replace(/\D/g, '');
const cedula = (body.cedula || '').trim();

if (!phone) {
  return [{ json: { ok: 'false', error: 'phone requerido' } }];
}

return [{ json: { phone, cedula } }];

const participant = $('Buscar Participante').first().json;
const phone = $('Validar Input').first().json.phone;

if (!participant || !participant.id) {
  return [{ json: { ok: 'true', existe: 'false', phone } }];
}

return [{ json: {
  ok: 'true',
  existe: 'true',
  phone,
  estado: participant.estado || '',
  nombre: participant.nombre_piloto || '',
  codigo: participant.codigo_preregistro || '',
} }];
